import json

wifi_results_file = locals()['var_functions.execute_python:30']
print('Loading from file:', wifi_results_file)

with open(wifi_results_file, 'r') as f:
    wifi_results = json.load(f)

wifi_businesses = wifi_results['wifi_businesses_list']

# Get PA WiFi-enabled businesses (not 'no')
pa_wifi_businesses = []
for business in wifi_businesses:
    if business.get('state') == 'PA' and 'no' not in str(business.get('wifi', '')).lower():
        pa_wifi_businesses.append({
            'business_id': business['business_id'],
            'wifi': business['wifi']
        })

print('PA WiFi-enabled businesses:', len(pa_wifi_businesses))
for i, business in enumerate(pa_wifi_businesses):
    print(f"  {i+1}. {business['business_id']} - {business['wifi']}")

print('__RESULT__:')
result = {
    'pa_wifi_businesses': pa_wifi_businesses,
    'count': len(pa_wifi_businesses)
}
print(json.dumps(result))

